package server.base.org.apache.accumulo.server.util;

public class AccumuloStatus { public static boolean isAccumuloOffline ( IZooReader reader , String rootPath ) throws IOException { try { for ( String child : reader . getChildren ( rootPath + Constants . ZTSERVERS ) ) { if ( ! reader . getChildren ( rootPath + Constants . ZTSERVERS + "/" + child ) . isEmpty ( ) ) return false ; } if ( ! reader . getChildren ( rootPath + Constants . ZMASTER_LOCK ) . isEmpty ( ) ) return false ; if ( ! reader . getChildren ( rootPath + Constants . ZMONITOR_LOCK ) . isEmpty ( ) ) return false ; if ( ! reader . getChildren ( rootPath + Constants . ZGC_LOCK ) . isEmpty ( ) ) return false ; } catch ( KeeperException e ) { throw new IOException ( "Issues contacting ZooKeeper to get Accumulo status." , e ) ; } catch ( InterruptedException e ) { throw new IOException ( "Issues contacting ZooKeeper to get Accumulo status." , e ) ; } return true ; } }